    foreach (var prop in aiFuncType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
    {
        var getset = $"{(prop.CanRead ? "get;" : "")} {(prop.CanWrite ? "set;" : "")}".Trim();
        Console.WriteLine($"  public {prop.PropertyType.Name} {prop.Name} {{ {getset} }}");
